private static <E extends Element> Integer indexInList(Element search, List<E> elements) {
    Validate.notNull(search);
    Validate.notNull(elements);
    int index = 0;
    for (E element : elements) {
        if (element != null) {
            if (element == search) {
                return index;
            }
        } else {
            // No match found
            return -1;
        }
        index++;
    }
    return -1;
}
